};

function makeCommitView(
  id: string,
  overrides: Partial<ReconcileCommitView> = {},
): ReconcileCommitView {
  return {
    commitId: id,
    currentTitle: `Commit ${id}`,
    currentChessPiece: "PAWN",
    currentEstimatePoints: 3,
    currentOutcome: null,
    currentOutcomeNotes: null,
    baselineSnapshot: {
      title: `Commit ${id}`,
      chessPiece: "PAWN",
      estimatePoints: 3,
      rcdoNodeId: null,
    },
