package com.weeklycommit.ai.dto;

import java.time.LocalDate;
import java.util.List;
import java.util.UUID;

/**
 * AI-generated team summary for a manager's weekly view.
 *
 * <p>
 * All cited items reference actual database objects so managers can drill down.
 * Only visible to team managers (not peers).
 */
public record ManagerAiSummaryResponse(
		/** {@code false} when AI is disabled or unavailable. */
		boolean aiAvailable,
		/** Stored suggestion id (null when unavailable). */
		UUID suggestionId,
		/** Team id this summary covers. */
		UUID teamId,
		/** Week start date this summary covers. */
		LocalDate weekStart,
		/** Prose summary of the team week. */
		String summaryText,
		/** RCDO branch titles with highest planned commitment this week. */
		List<String> topRcdoBranches,
		/** Unresolved exception ids (cited objects). */
		List<UUID> unresolvedExceptionIds,
		/** Textual patterns about carry-forwards (cited from plan data). */
		List<String> carryForwardPatterns,
		/** Work item ids for King/Queen commits currently BLOCKED (cited objects). */
		List<UUID> criticalBlockedItemIds,
		/** Model version for audit. */
		String modelVersion) {

	/** Convenience factory for the unavailable case. */
	public static ManagerAiSummaryResponse unavailable(UUID teamId, LocalDate weekStart) {
		return new ManagerAiSummaryResponse(false, null, teamId, weekStart, null, List.of(), List.of(), List.of(),
				List.of(), null);
	}
}

package com.weeklycommit.ai.controller;

import com.fasterxml.jackson.databind.JsonNode;
import com.fasterxml.jackson.databind.ObjectMapper;
import com.weeklycommit.ai.dto.AiFeedbackRequest;
import com.weeklycommit.ai.dto.CommitDraftAssistRequest;
import com.weeklycommit.ai.dto.CommitDraftAssistResponse;
import com.weeklycommit.ai.dto.CommitLintRequest;
import com.weeklycommit.ai.dto.CommitLintResponse;
import com.weeklycommit.ai.dto.InsightCardDto;
import com.weeklycommit.ai.dto.InsightListResponse;
import com.weeklycommit.ai.dto.ManagerAiSummaryResponse;
import com.weeklycommit.ai.dto.RagQueryRequest;
import com.weeklycommit.ai.dto.RagQueryResponse;
import com.weeklycommit.ai.dto.RagSourceDto;
import com.weeklycommit.ai.dto.RcdoSuggestRequest;
import com.weeklycommit.ai.dto.RcdoSuggestResponse;
import com.weeklycommit.ai.dto.ReconcileAssistRequest;
import com.weeklycommit.ai.dto.ReconcileAssistResponse;
import com.weeklycommit.ai.dto.RiskSignalResponse.PlanRiskSignals;
import com.weeklycommit.ai.provider.AiContext;
import com.weeklycommit.ai.provider.AiProvider;
import com.weeklycommit.ai.provider.AiProviderRegistry;
import com.weeklycommit.ai.rag.SemanticIndexService;
import com.weeklycommit.ai.rag.SemanticQueryService;
import com.weeklycommit.ai.service.AiSuggestionService;
import com.weeklycommit.ai.service.CommitDraftAssistService;
import com.weeklycommit.ai.service.CommitLintService;
import com.weeklycommit.ai.service.ManagerAiSummaryService;
import com.weeklycommit.ai.service.RcdoSuggestService;
import com.weeklycommit.ai.service.RiskDetectionService;
import com.weeklycommit.ai.service.ReconcileAssistService;
import com.weeklycommit.domain.entity.AiSuggestion;
import com.weeklycommit.domain.repository.AiSuggestionRepository;
import jakarta.validation.Valid;
import java.time.LocalDate;
import java.util.ArrayList;
import java.util.List;
import java.util.UUID;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.format.annotation.DateTimeFormat;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.PathVariable;
import org.springframework.web.bind.annotation.PostMapping;
import org.springframework.web.bind.annotation.RequestBody;
import org.springframework.web.bind.annotation.RequestHeader;
import org.springframework.web.bind.annotation.RestController;

/**
 * REST endpoints for AI-powered commit assistance, linting, RCDO suggestions,
 * risk detection, reconciliation assistance, manager summaries, RAG queries,
 * and proactive insight retrieval.
 *
 * <p>
 * All endpoints degrade gracefully: when AI is disabled or unavailable the
 * response includes {@code aiAvailable: false} and no error is returned. Core
 * workflow is never blocked by AI unavailability.
 */
@RestController
public class AiController {

	private static final Logger log = LoggerFactory.getLogger(AiController.class);

	private final CommitDraftAssistService draftAssistService;
	private final CommitLintService lintService;
	private final RcdoSuggestService rcdoSuggestService;
	private final RiskDetectionService riskDetectionService;
	private final ReconcileAssistService reconcileAssistService;
	private final ManagerAiSummaryService managerSummaryService;
	private final AiSuggestionService suggestionService;
	private final AiProviderRegistry providerRegistry;
	private final SemanticIndexService semanticIndexService;
	private final SemanticQueryService semanticQueryService;
	private final AiSuggestionRepository suggestionRepo;
	private final ObjectMapper objectMapper;

	public AiController(CommitDraftAssistService draftAssistService, CommitLintService lintService,
			RcdoSuggestService rcdoSuggestService, RiskDetectionService riskDetectionService,
			ReconcileAssistService reconcileAssistService, ManagerAiSummaryService managerSummaryService,
			AiSuggestionService suggestionService, AiProviderRegistry providerRegistry,
			SemanticIndexService semanticIndexService, SemanticQueryService semanticQueryService,
			AiSuggestionRepository suggestionRepo, ObjectMapper objectMapper) {
		this.draftAssistService = draftAssistService;
		this.lintService = lintService;
		this.rcdoSuggestService = rcdoSuggestService;
		this.riskDetectionService = riskDetectionService;
		this.reconcileAssistService = reconcileAssistService;
		this.managerSummaryService = managerSummaryService;
		this.suggestionService = suggestionService;
		this.providerRegistry = providerRegistry;
		this.semanticIndexService = semanticIndexService;
		this.semanticQueryService = semanticQueryService;
		this.suggestionRepo = suggestionRepo;
		this.objectMapper = objectMapper;
	}

	// -------------------------------------------------------------------------
	// Capability 1: Commit draft assistance
	// -------------------------------------------------------------------------

	/**
	 * Returns suggestions for improving a commit draft (title, description, success
	 * criteria, estimate). Suggestions are editable proposals — never auto-applied.
	 */
	@PostMapping("/api/ai/commit-draft-assist")
	public ResponseEntity<CommitDraftAssistResponse> commitDraftAssist(
			@Valid @RequestBody CommitDraftAssistRequest request) {
		return ResponseEntity.ok(draftAssistService.assist(request));
	}

	// -------------------------------------------------------------------------
	// Capability 2: Commit quality lint
	// -------------------------------------------------------------------------

	/**
	 * Runs commit quality lint for a plan. Returns {@code hardValidation} (blocks
	 * lock) and {@code softGuidance} (informational) messages.
	 */
	@PostMapping("/api/ai/commit-lint")
	public ResponseEntity<CommitLintResponse> commitLint(@Valid @RequestBody CommitLintRequest request) {
		return ResponseEntity.ok(lintService.lint(request));
	}

	// -------------------------------------------------------------------------
	// Capability 3: RCDO link suggestion
	// -------------------------------------------------------------------------

	/**
	 * Suggests a primary RCDO node for a commit draft. Only surfaced when
	 * confidence &ge; 0.7. Never auto-links.
	 */
	@PostMapping("/api/ai/rcdo-suggest")
	public ResponseEntity<RcdoSuggestResponse> rcdoSuggest(@Valid @RequestBody RcdoSuggestRequest request) {
		return ResponseEntity.ok(rcdoSuggestService.suggest(request));
	}

	// -------------------------------------------------------------------------
	// Capability 4: Risk signals
	// -------------------------------------------------------------------------

	/**
	 * Returns current risk signals for the given plan. Hidden from peers — only the
	 * plan owner and their manager should call this endpoint.
	 */
	@GetMapping("/api/plans/{id}/risk-signals")
	public ResponseEntity<PlanRiskSignals> getRiskSignals(@PathVariable UUID id,
			@RequestHeader(value = "X-Actor-User-Id", required = false) UUID callerId) {
		if (callerId == null) {
			return ResponseEntity.badRequest().build();
		}
		return ResponseEntity.ok(riskDetectionService.getRiskSignals(id, callerId));
	}

	// -------------------------------------------------------------------------
	// Capability 5: Reconciliation assistance
	// -------------------------------------------------------------------------

	/**
	 * Returns reconciliation assistance: likely outcomes, draft summary, and
	 * carry-forward recommendations for a plan entering the reconcile phase.
	 */
	@PostMapping("/api/ai/reconcile-assist")
	public ResponseEntity<ReconcileAssistResponse> reconcileAssist(@Valid @RequestBody ReconcileAssistRequest request) {
		return ResponseEntity.ok(reconcileAssistService.assist(request));
	}

	// -------------------------------------------------------------------------
	// Capability 6: Manager team AI summary
	// -------------------------------------------------------------------------

	/**
	 * Returns the AI-generated team summary for the given week. Only accessible to
	 * managers.
	 */
	@GetMapping("/api/teams/{id}/week/{weekStart}/ai-summary")
	public ResponseEntity<ManagerAiSummaryResponse> getTeamAiSummary(@PathVariable UUID id,
			@PathVariable @DateTimeFormat(iso = DateTimeFormat.ISO.DATE) LocalDate weekStart,
			@RequestHeader(value = "X-Actor-User-Id", required = false) UUID callerId) {
		return ResponseEntity.ok(managerSummaryService.getSummary(id, weekStart, callerId));
	}

	// -------------------------------------------------------------------------
	// Capability 7: RAG query
	// -------------------------------------------------------------------------

	/**
	 * Executes a semantic (RAG) query against the team's indexed planning history.
	 * Returns an AI-generated answer with source citations.
	 *
	 * <p>
	 * Degrades gracefully: returns {@code {aiAvailable: false}} when Pinecone or
	 * the LLM is unavailable.
	 */
	@PostMapping("/api/ai/query")
	public ResponseEntity<RagQueryResponse> ragQuery(@Valid @RequestBody RagQueryRequest request) {
		try {
			SemanticQueryService.RagQueryResult result = semanticQueryService.query(request.question(),
					request.teamId(), request.userId());
			if (!result.available()) {
				return ResponseEntity.ok(RagQueryResponse.unavailable());
			}
			List<RagSourceDto> sources = result.sources().stream()
					.map(s -> new RagSourceDto(s.entityType(), s.entityId(), s.weekStartDate(), s.snippet())).toList();
			return ResponseEntity.ok(
					new RagQueryResponse(true, result.answer(), sources, result.confidence(), result.suggestionId()));
		} catch (Exception ex) {
			log.warn("RAG query failed: {}", ex.getMessage());
			return ResponseEntity.ok(RagQueryResponse.unavailable());
		}
	}

	// -------------------------------------------------------------------------
	// Capability 8: Team AI insights
	// -------------------------------------------------------------------------

	/**
	 * Returns persisted TEAM_INSIGHT rows for the given team and week.
	 *
	 * <p>
	 * Insights are generated by the scheduled job in
	 * {@link com.weeklycommit.ai.rag.InsightGenerationService}. This endpoint reads
	 * them back from the {@code ai_suggestion} table.
	 */
	@GetMapping("/api/teams/{id}/week/{weekStart}/ai-insights")
	public ResponseEntity<InsightListResponse> getTeamInsights(@PathVariable UUID id,
			@PathVariable @DateTimeFormat(iso = DateTimeFormat.ISO.DATE) LocalDate weekStart) {
		try {
			List<AiSuggestion> rows = suggestionRepo.findByTeamIdAndWeekStartDateAndSuggestionType(id, weekStart,
					AiContext.TYPE_TEAM_INSIGHT);
			List<InsightCardDto> insights = parseInsightCards(rows);
			return ResponseEntity.ok(new InsightListResponse(true, insights));
		} catch (Exception ex) {
			log.warn("Failed to retrieve team insights for team={}, week={}: {}", id, weekStart, ex.getMessage());
			return ResponseEntity.ok(InsightListResponse.unavailable());
		}
	}

	// -------------------------------------------------------------------------
	// Capability 9: Personal (plan) AI insights
	// -------------------------------------------------------------------------

	/**
	 * Returns persisted PERSONAL_INSIGHT rows for the given plan.
	 *
	 * <p>
	 * Insights are generated on plan lock (via
	 * {@link com.weeklycommit.ai.rag.InsightGenerationService#generatePersonalInsightsAsync})
	 * and by the daily sweep.
	 */
	@GetMapping("/api/plans/{id}/ai-insights")
	public ResponseEntity<InsightListResponse> getPlanInsights(@PathVariable UUID id) {
		try {
			List<AiSuggestion> rows = suggestionRepo.findByPlanIdAndSuggestionType(id, AiContext.TYPE_PERSONAL_INSIGHT);
			List<InsightCardDto> insights = parseInsightCards(rows);
			return ResponseEntity.ok(new InsightListResponse(true, insights));
		} catch (Exception ex) {
			log.warn("Failed to retrieve personal insights for plan={}: {}", id, ex.getMessage());
			return ResponseEntity.ok(InsightListResponse.unavailable());
		}
	}

	// -------------------------------------------------------------------------
	// Admin: full reindex
	// -------------------------------------------------------------------------

	/**
	 * Triggers an async full reindex of all plans into Pinecone. Returns
	 * immediately; indexing runs in a background thread. Intended for dev/admin use
	 * after bulk SQL seed or Pinecone wipes.
	 */
	@PostMapping("/api/admin/ai/reindex")
	public ResponseEntity<java.util.Map<String, Object>> triggerFullReindex() {
		log.info("Admin full reindex triggered");
		int count = semanticIndexService.fullReindex();
		java.util.LinkedHashMap<String, Object> result = new java.util.LinkedHashMap<>();
		result.put("plansQueued", count);
		result.put("status", count > 0 ? "indexing_started" : "pinecone_unavailable");
		result.put("message",
				count > 0
						? "Indexing " + count + " plans in background. Check server logs for completion."
						: "Pinecone not configured.");
		return ResponseEntity.ok(result);
	}

	// -------------------------------------------------------------------------
	// AI Status
	// -------------------------------------------------------------------------

	/**
	 * Returns the current AI provider status: enabled, provider name/version,
	 * availability. Useful for ops dashboards and frontend feature checks.
	 */
	@GetMapping("/api/ai/status")
	public ResponseEntity<java.util.Map<String, Object>> getAiStatus() {
		java.util.Optional<AiProvider> active = providerRegistry.getActiveProvider();
		java.util.Map<String, Object> status = new java.util.LinkedHashMap<>();
		status.put("aiEnabled", providerRegistry.isAiEnabled());
		status.put("providerName", active.map(AiProvider::getName).orElse("none"));
		status.put("providerVersion", active.map(AiProvider::getVersion).orElse("none"));
		status.put("available", active.map(AiProvider::isAvailable).orElse(false));
		return ResponseEntity.ok(status);
	}

	// -------------------------------------------------------------------------
	// Feedback
	// -------------------------------------------------------------------------

	/**
	 * Records user feedback (ACCEPTED / DISMISSED / EDITED) on an AI suggestion.
	 */
	@PostMapping("/api/ai/feedback")
	public ResponseEntity<Void> recordFeedback(@Valid @RequestBody AiFeedbackRequest request) {
		suggestionService.recordFeedback(request);
		return ResponseEntity.status(HttpStatus.CREATED).build();
	}

	// -------------------------------------------------------------------------
	// Private helpers
	// -------------------------------------------------------------------------

	/**
	 * Parses each {@link AiSuggestion}'s {@code suggestionPayload} JSON into an
	 * {@link InsightCardDto}. Rows whose payload cannot be parsed are silently
	 * skipped.
	 */
	private List<InsightCardDto> parseInsightCards(List<AiSuggestion> rows) {
		List<InsightCardDto> result = new ArrayList<>(rows.size());
		for (AiSuggestion row : rows) {
			try {
				JsonNode root = objectMapper.readTree(row.getSuggestionPayload());
				String insightText = root.path("insightText").asText(row.getRationale());
				String severity = root.path("severity").asText("LOW");
				String actionSuggestion = root.path("actionSuggestion").asText("");
				List<String> sourceEntityIds = new ArrayList<>();
				JsonNode idsNode = root.path("sourceEntityIds");
				if (idsNode.isArray()) {
					for (JsonNode n : idsNode) {
						sourceEntityIds.add(n.asText());
					}
				}
				String createdAt = row.getCreatedAt() != null ? row.getCreatedAt().toString() : "";
				result.add(new InsightCardDto(row.getId(), insightText, severity, sourceEntityIds, actionSuggestion,
						createdAt));
			} catch (Exception ex) {
				log.debug("Skipping unparseable insight payload for suggestion {}: {}", row.getId(), ex.getMessage());
			}
		}
		return result;
	}
}

package com.weeklycommit.ai.dto;

import com.weeklycommit.domain.enums.ChessPiece;
import java.util.UUID;

/**
 * Suggestion returned for commit drafting assistance.
 *
 * <p>
 * All suggestion fields are editable proposals — they are never auto-applied.
 * When {@code aiAvailable} is {@code false}, all suggestion fields are null.
 */
public record CommitDraftAssistResponse(
		/** {@code false} when AI is disabled or unavailable. */
		boolean aiAvailable,
		/** Stored suggestion id (null when unavailable). */
		UUID suggestionId,
		/** Proposed improved title. */
		String suggestedTitle,
		/** Proposed improved description. */
		String suggestedDescription,
		/** Proposed success criteria (especially for King/Queen). */
		String suggestedSuccessCriteria,
		/** Proposed estimate in story points. */
		Integer suggestedEstimatePoints,
		/**
		 * Suggested chess piece classification. Null when the current chess piece is
		 * already appropriate or when chessPiece was already specified in the request.
		 */
		ChessPiece suggestedChessPiece,
		/** Explanation of why these suggestions were generated. */
		String rationale) {

	/** Convenience factory for the unavailable case. */
	public static CommitDraftAssistResponse unavailable() {
		return new CommitDraftAssistResponse(false, null, null, null, null, null, null, null);
	}
}

package com.weeklycommit.ai.service;

import com.fasterxml.jackson.core.JsonProcessingException;
import com.fasterxml.jackson.databind.JsonNode;
import com.fasterxml.jackson.databind.ObjectMapper;
import com.weeklycommit.ai.dto.CommitDraftAssistRequest;
import com.weeklycommit.ai.dto.CommitDraftAssistResponse;
import com.weeklycommit.ai.provider.AiContext;
import com.weeklycommit.ai.provider.AiProviderRegistry;
import com.weeklycommit.ai.provider.AiSuggestionResult;
import com.weeklycommit.domain.entity.AiSuggestion;
import com.weeklycommit.domain.entity.WeeklyCommit;
import com.weeklycommit.domain.entity.WeeklyPlan;
import com.weeklycommit.domain.enums.ChessPiece;
import com.weeklycommit.domain.repository.WeeklyCommitRepository;
import com.weeklycommit.domain.repository.WeeklyPlanRepository;
import com.weeklycommit.rcdo.exception.ResourceNotFoundException;
import java.util.ArrayList;
import java.util.HashMap;
import java.util.List;
import java.util.Map;
import java.util.UUID;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

/**
 * Provides commit drafting assistance (PRD §17 capability 1).
 *
 * <p>
 * Suggestions are editable proposals — they are never auto-applied.
 */
@Service
@Transactional
public class CommitDraftAssistService {

	private static final Logger log = LoggerFactory.getLogger(CommitDraftAssistService.class);

	private final AiProviderRegistry registry;
	private final AiSuggestionService suggestionService;
	private final WeeklyPlanRepository planRepo;
	private final WeeklyCommitRepository commitRepo;
	private final ObjectMapper objectMapper;

	public CommitDraftAssistService(AiProviderRegistry registry, AiSuggestionService suggestionService,
			WeeklyPlanRepository planRepo, WeeklyCommitRepository commitRepo, ObjectMapper objectMapper) {
		this.registry = registry;
		this.suggestionService = suggestionService;
		this.planRepo = planRepo;
		this.commitRepo = commitRepo;
		this.objectMapper = objectMapper;
	}

	/**
	 * Generates commit drafting suggestions for a commit being authored.
	 *
	 * @param request
	 *            the drafting assist request
	 * @return suggestions, or a response with {@code aiAvailable=false} if AI is
	 *         unavailable
	 */
	public CommitDraftAssistResponse assist(CommitDraftAssistRequest request) {
		if (!registry.isAiEnabled()) {
			return CommitDraftAssistResponse.unavailable();
		}

		WeeklyPlan plan = planRepo.findById(request.planId())
				.orElseThrow(() -> new ResourceNotFoundException("Plan not found: " + request.planId()));

		List<WeeklyCommit> pastCommits = commitRepo.findByOwnerUserId(plan.getOwnerUserId());

		Map<String, Object> commitData = new HashMap<>();
		commitData.put("title", request.currentTitle());
		commitData.put("description", request.currentDescription());
		commitData.put("successCriteria", request.currentSuccessCriteria());
		commitData.put("estimatePoints", request.currentEstimatePoints());
		commitData.put("chessPiece", request.chessPiece() != null ? request.chessPiece().name() : null);

		Map<String, Object> planData = new HashMap<>();
		planData.put("weekStartDate", plan.getWeekStartDate().toString());
		planData.put("capacityPoints", plan.getCapacityBudgetPoints());

		List<Map<String, Object>> historical = new ArrayList<>();
		for (WeeklyCommit c : pastCommits) {
			Map<String, Object> entry = new HashMap<>();
			entry.put("title", c.getTitle());
			entry.put("estimatePoints", c.getEstimatePoints());
			entry.put("chessPiece", c.getChessPiece() != null ? c.getChessPiece().name() : null);
			historical.add(entry);
		}

		String contextJson = toJson(Map.of("commit", commitData, "plan", planData));

		AiContext context = new AiContext(AiContext.TYPE_COMMIT_DRAFT, request.userId(), request.planId(),
				request.commitId(), commitData, planData, historical, List.of(), Map.of());

		AiSuggestionResult result = registry.generateSuggestion(context);
		if (!result.available()) {
			return CommitDraftAssistResponse.unavailable();
		}

		AiSuggestion stored = suggestionService.storeSuggestion(AiContext.TYPE_COMMIT_DRAFT, request.userId(),
				request.planId(), request.commitId(), contextJson, result);

		return parseResponse(stored.getId(), result);
	}

	// -------------------------------------------------------------------------
	// Private helpers
	// -------------------------------------------------------------------------

	private CommitDraftAssistResponse parseResponse(UUID suggestionId, AiSuggestionResult result) {
		try {
			JsonNode node = objectMapper.readTree(result.payload());
			return new CommitDraftAssistResponse(true, suggestionId, textOrNull(node, "suggestedTitle"),
					textOrNull(node, "suggestedDescription"), textOrNull(node, "suggestedSuccessCriteria"),
					node.has("suggestedEstimatePoints") && !node.get("suggestedEstimatePoints").isNull()
							? node.get("suggestedEstimatePoints").asInt()
							: null,
					parseChessPiece(node, "suggestedChessPiece"), result.rationale());
		} catch (JsonProcessingException e) {
			log.warn("Failed to parse AI draft assist payload: {}", e.getMessage());
			return CommitDraftAssistResponse.unavailable();
		}
	}

	private static ChessPiece parseChessPiece(JsonNode node, String field) {
		JsonNode child = node.get(field);
		if (child == null || child.isNull() || child.asText().isBlank()) {
			return null;
		}
		try {
			return ChessPiece.valueOf(child.asText().trim().toUpperCase());
		} catch (IllegalArgumentException e) {
			return null;
		}
	}

	private static String textOrNull(JsonNode node, String field) {
		JsonNode child = node.get(field);
		if (child == null || child.isNull() || child.asText().isBlank()) {
			return null;
		}
		return child.asText();
	}

	private String toJson(Object obj) {
		try {
			return objectMapper.writeValueAsString(obj);
		} catch (JsonProcessingException e) {
			return "{}";
		}
	}
}

package com.weeklycommit.ai.service;

import static org.assertj.core.api.Assertions.assertThat;
import static org.mockito.ArgumentMatchers.any;
import static org.mockito.ArgumentMatchers.anyString;
import static org.mockito.Mockito.verify;
import static org.mockito.Mockito.when;

import com.fasterxml.jackson.databind.ObjectMapper;
import com.weeklycommit.ai.dto.CommitDraftAssistRequest;
import com.weeklycommit.ai.dto.CommitDraftAssistResponse;
import com.weeklycommit.ai.provider.AiProviderRegistry;
import com.weeklycommit.ai.provider.AiSuggestionResult;
import com.weeklycommit.domain.entity.AiSuggestion;
import com.weeklycommit.domain.entity.WeeklyPlan;
import com.weeklycommit.domain.enums.ChessPiece;
import com.weeklycommit.domain.repository.WeeklyCommitRepository;
import com.weeklycommit.domain.repository.WeeklyPlanRepository;
import java.time.LocalDate;
import java.util.List;
import java.util.Optional;
import java.util.UUID;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.extension.ExtendWith;
import org.mockito.Mock;
import org.mockito.junit.jupiter.MockitoExtension;

@ExtendWith(MockitoExtension.class)
class CommitDraftAssistServiceTest {

	@Mock
	private AiProviderRegistry registry;

	@Mock
	private AiSuggestionService suggestionService;

	@Mock
	private WeeklyPlanRepository planRepo;

	@Mock
	private WeeklyCommitRepository commitRepo;

	private CommitDraftAssistService service;

	private UUID planId;
	private UUID userId;
	private WeeklyPlan plan;

	@BeforeEach
	void setUp() {
		service = new CommitDraftAssistService(registry, suggestionService, planRepo, commitRepo, new ObjectMapper());
		planId = UUID.randomUUID();
		userId = UUID.randomUUID();

		plan = new WeeklyPlan();
		plan.setId(planId);
		plan.setOwnerUserId(userId);
		plan.setWeekStartDate(LocalDate.of(2026, 3, 23));
		plan.setCapacityBudgetPoints(10);
	}

	// -------------------------------------------------------------------------
	// AI disabled
	// -------------------------------------------------------------------------

	@Test
	void assist_whenAiDisabled_returnsUnavailable() {
		when(registry.isAiEnabled()).thenReturn(false);

		CommitDraftAssistRequest req = new CommitDraftAssistRequest(planId, userId, null, "Do stuff", null, null, null,
				ChessPiece.PAWN);
		CommitDraftAssistResponse resp = service.assist(req);

		assertThat(resp.aiAvailable()).isFalse();
		assertThat(resp.suggestedTitle()).isNull();
	}

	// -------------------------------------------------------------------------
	// AI available — returns suggestions
	// -------------------------------------------------------------------------

	@Test
	void assist_whenAiAvailable_returnsStructuredSuggestions() throws Exception {
		when(registry.isAiEnabled()).thenReturn(true);
		when(planRepo.findById(planId)).thenReturn(Optional.of(plan));
		when(commitRepo.findByOwnerUserId(userId)).thenReturn(List.of());

		String payload = "{\"suggestedTitle\":\"Better Title\"," + "\"suggestedDescription\":\"Better desc\","
				+ "\"suggestedSuccessCriteria\":\"Criteria\"," + "\"suggestedEstimatePoints\":3,"
				+ "\"suggestedChessPiece\":null}";
		AiSuggestionResult result = new AiSuggestionResult(true, payload, "test rationale", 0.85, "stub-v1");
		when(registry.generateSuggestion(any())).thenReturn(result);

		AiSuggestion stored = new AiSuggestion();
		UUID suggestionId = UUID.randomUUID();
		stored.setId(suggestionId);
		when(suggestionService.storeSuggestion(anyString(), any(), any(), any(), anyString(), any()))
				.thenReturn(stored);

		CommitDraftAssistRequest req = new CommitDraftAssistRequest(planId, userId, null, "Do stuff", null, null, null,
				ChessPiece.KING);
		CommitDraftAssistResponse resp = service.assist(req);

		assertThat(resp.aiAvailable()).isTrue();
		assertThat(resp.suggestionId()).isEqualTo(suggestionId);
		assertThat(resp.suggestedTitle()).isEqualTo("Better Title");
		assertThat(resp.suggestedDescription()).isEqualTo("Better desc");
		assertThat(resp.suggestedSuccessCriteria()).isEqualTo("Criteria");
		assertThat(resp.suggestedEstimatePoints()).isEqualTo(3);
		assertThat(resp.suggestedChessPiece()).isNull();
		assertThat(resp.rationale()).isEqualTo("test rationale");
	}

	@Test
	void assist_whenChessPieceInferred_returnsSuggestedChessPiece() throws Exception {
		when(registry.isAiEnabled()).thenReturn(true);
		when(planRepo.findById(planId)).thenReturn(Optional.of(plan));
		when(commitRepo.findByOwnerUserId(userId)).thenReturn(List.of());

		String payload = "{\"suggestedTitle\":\"Configure Pinecone index and run initial ingestion\","
				+ "\"suggestedDescription\":null," + "\"suggestedSuccessCriteria\":\"Pinecone index created\","
				+ "\"suggestedEstimatePoints\":3," + "\"suggestedChessPiece\":\"BISHOP\"}";
		AiSuggestionResult result = new AiSuggestionResult(true, payload, "inferred from description", 0.8, "stub-v1");
		when(registry.generateSuggestion(any())).thenReturn(result);

		AiSuggestion stored = new AiSuggestion();
		stored.setId(UUID.randomUUID());
		when(suggestionService.storeSuggestion(anyString(), any(), any(), any(), anyString(), any()))
				.thenReturn(stored);

		// chessPiece is null — freeform mode
		CommitDraftAssistRequest req = new CommitDraftAssistRequest(planId, userId, null,
				"set up Pinecone vector index for planning data", null, null, null, null);
		CommitDraftAssistResponse resp = service.assist(req);

		assertThat(resp.aiAvailable()).isTrue();
		assertThat(resp.suggestedChessPiece()).isEqualTo(ChessPiece.BISHOP);
		assertThat(resp.suggestedTitle()).isEqualTo("Configure Pinecone index and run initial ingestion");
	}

	@Test
	void assist_whenChessPieceInvalidInPayload_returnsNullChessPiece() throws Exception {
		when(registry.isAiEnabled()).thenReturn(true);
		when(planRepo.findById(planId)).thenReturn(Optional.of(plan));
		when(commitRepo.findByOwnerUserId(userId)).thenReturn(List.of());

		String payload = "{\"suggestedTitle\":\"T\",\"suggestedDescription\":null,"
				+ "\"suggestedSuccessCriteria\":null,\"suggestedEstimatePoints\":null,"
				+ "\"suggestedChessPiece\":\"INVALID_PIECE\"}";
		AiSuggestionResult result = new AiSuggestionResult(true, payload, "rationale", 0.7, "stub-v1");
		when(registry.generateSuggestion(any())).thenReturn(result);

		AiSuggestion stored = new AiSuggestion();
		stored.setId(UUID.randomUUID());
		when(suggestionService.storeSuggestion(anyString(), any(), any(), any(), anyString(), any()))
				.thenReturn(stored);

		CommitDraftAssistRequest req = new CommitDraftAssistRequest(planId, userId, null, "T", null, null, null, null);
		CommitDraftAssistResponse resp = service.assist(req);

		assertThat(resp.aiAvailable()).isTrue();
		// Invalid enum value must default to null, not throw
		assertThat(resp.suggestedChessPiece()).isNull();
	}

	@Test
	void assist_whenAiResultUnavailable_returnsUnavailable() {
		when(registry.isAiEnabled()).thenReturn(true);
		when(planRepo.findById(planId)).thenReturn(Optional.of(plan));
		when(commitRepo.findByOwnerUserId(userId)).thenReturn(List.of());
		when(registry.generateSuggestion(any())).thenReturn(AiSuggestionResult.unavailable());

		CommitDraftAssistRequest req = new CommitDraftAssistRequest(planId, userId, null, "Do stuff", null, null, null,
				ChessPiece.PAWN);
		CommitDraftAssistResponse resp = service.assist(req);

		assertThat(resp.aiAvailable()).isFalse();
	}

	@Test
	void assist_storesSuggestionInDb() throws Exception {
		when(registry.isAiEnabled()).thenReturn(true);
		when(planRepo.findById(planId)).thenReturn(Optional.of(plan));
		when(commitRepo.findByOwnerUserId(userId)).thenReturn(List.of());

		String payload = "{\"suggestedTitle\":\"T\",\"suggestedDescription\":\"D\","
				+ "\"suggestedSuccessCriteria\":null,\"suggestedEstimatePoints\":null}";
		AiSuggestionResult result = new AiSuggestionResult(true, payload, "rationale", 0.8, "stub-v1");
		when(registry.generateSuggestion(any())).thenReturn(result);

		AiSuggestion stored = new AiSuggestion();
		stored.setId(UUID.randomUUID());
		when(suggestionService.storeSuggestion(anyString(), any(), any(), any(), anyString(), any()))
				.thenReturn(stored);

		CommitDraftAssistRequest req = new CommitDraftAssistRequest(planId, userId, null, "title", null, null, null,
				ChessPiece.ROOK);
		service.assist(req);

		verify(suggestionService).storeSuggestion(anyString(), any(), any(), any(), anyString(), any());
	}
}

/**
 * AI API client functions for all AI-powered endpoints.
 */
import type { ApiClient } from "./client.js";

// ── Types ─────────────────────────────────────────────────────────────────────

export interface AiStatusResponse {
  aiEnabled: boolean;
  providerName: string;
  providerVersion: string;
  available: boolean;
}

export interface CommitDraftAssistRequest {
  userId: string;
  planId: string;
  commitId?: string | undefined;
  currentTitle: string;
  currentDescription?: string | undefined;
  currentSuccessCriteria?: string | undefined;
  currentEstimatePoints?: number | undefined;
  chessPiece?: string | undefined;
}

export interface CommitDraftAssistResponse {
  aiAvailable: boolean;
  suggestionId?: string;
  suggestedTitle?: string | null;
  suggestedDescription?: string | null;
  suggestedSuccessCriteria?: string | null;
  suggestedEstimatePoints?: number | null;
  /** Suggested chess piece. Non-null only when chessPiece was absent in the request. */
  suggestedChessPiece?: string | null;
  rationale?: string;
}

export interface CommitLintRequest {
  userId: string;
  planId: string;
}

export interface LintMessage {
  code: string;
  message: string;
  commitId?: string;
}

export interface CommitLintResponse {
  aiAvailable: boolean;
  suggestionId?: string;
  hardValidation: LintMessage[];
  softGuidance: LintMessage[];
  rationale?: string;
}

export interface RiskSignal {
  id: string;
  signalType: string;
  rationale: string;
  planId: string;
  commitId?: string | null;
  createdAt: string;
}

export interface PlanRiskSignalsResponse {
  aiAvailable: boolean;
  planId: string;
  signals: RiskSignal[];
}

// ── Reconcile Assist types ─────────────────────────────────────────────────

export interface ReconcileAssistRequest {
  planId: string;
  userId: string;
}

export interface CommitOutcomeSuggestion {
  commitId: string;
  commitTitle: string;
  suggestedOutcome: string;
  rationale: string;
}

export interface CarryForwardRecommendation {
  commitId: string;
  commitTitle: string;
  rationale: string;
}

export interface ReconcileAssistResponse {
  aiAvailable: boolean;
  suggestionId?: string;
  likelyOutcomes: CommitOutcomeSuggestion[];
  draftSummary?: string | null;
  carryForwardRecommendations: CarryForwardRecommendation[];
}

export type FeedbackAction = "ACCEPTED" | "DISMISSED" | "EDITED";

export interface AiFeedbackRequest {
  suggestionId: string;
  userId: string;
  action: FeedbackAction;
  notes?: string;
}

// ── Manager AI Summary types ──────────────────────────────────────────────────

export interface ManagerAiSummaryResponse {
  aiAvailable: boolean;
  /** Stored suggestion id for feedback (null when unavailable). */
  suggestionId?: string | null;
  teamId: string;
  weekStart: string;
  /** Prose summary of the team week. Null when aiAvailable=false. */
  summaryText?: string | null;
  /** RCDO branch titles with highest planned commitment this week. */
  topRcdoBranches: string[];
  /** Unresolved exception ids (cited objects). */
  unresolvedExceptionIds: string[];
  /** Textual carry-forward patterns (cited from plan data). */
  carryForwardPatterns: string[];
  /** Work item ids for King/Queen commits currently BLOCKED (cited objects). */
  criticalBlockedItemIds: string[];
  modelVersion?: string | null;
}

// ── API factory ───────────────────────────────────────────────────────────────

export function createAiApi(client: ApiClient, actorUserId: string) {
  const actorHeader = { "X-Actor-User-Id": actorUserId };

  return {
    /** GET /api/ai/status — provider health/availability check. */
    getStatus: (): Promise<AiStatusResponse> =>
      client.get("/ai/status"),

    /** POST /api/ai/commit-draft-assist — get draft improvement suggestions. */
    commitDraftAssist: (
      request: CommitDraftAssistRequest,
    ): Promise<CommitDraftAssistResponse> =>
      client.post("/ai/commit-draft-assist", request),

    /** POST /api/ai/commit-lint — run commit quality lint on a plan. */
    commitLint: (request: CommitLintRequest): Promise<CommitLintResponse> =>
      client.post("/ai/commit-lint", request),

    /** GET /api/plans/{id}/risk-signals — risk signals for a plan. */
    getRiskSignals: (planId: string): Promise<PlanRiskSignalsResponse> =>
      client.get(`/plans/${encodeURIComponent(planId)}/risk-signals`, {
        headers: actorHeader,
      }),

    /** POST /api/ai/reconcile-assist — get reconciliation suggestions. */
    reconcileAssist: (
      request: ReconcileAssistRequest,
    ): Promise<ReconcileAssistResponse> =>
      client.post("/ai/reconcile-assist", request),

    /** POST /api/ai/feedback — record thumbs up/down on a suggestion. */
    recordFeedback: (request: AiFeedbackRequest): Promise<void> =>
      client.post("/ai/feedback", request),

    /**
     * GET /api/teams/{id}/week/{weekStart}/ai-summary —
     * AI-generated manager team summary for the given team and week.
     *
     * @param teamId    team UUID string
     * @param weekStart ISO date string (YYYY-MM-DD) for the Monday of the week
     */
    getTeamAiSummary: (
      teamId: string,
      weekStart: string,
    ): Promise<ManagerAiSummaryResponse> =>
      client.get(
        `/teams/${encodeURIComponent(teamId)}/week/${encodeURIComponent(weekStart)}/ai-summary`,
        { headers: actorHeader },
      ),
  };
}

export type AiApi = ReturnType<typeof createAiApi>;

/**
 * CommitDraftAssistButton — "✨ AI Suggest" button that calls the existing
 * CommitDraftAssistService backend and renders inline suggestions.
 *
 * SOTA note: Completes the wiring of an existing backend capability to the
 * frontend (ai-eval-roadmap Phase 3a). Every suggestion shows rationale and
 * is accept/dismiss-able per PRD §17 ("assistive, not authoritarian").
 */
import { useState, useCallback } from "react";
import { Sparkles, Check, Loader2 } from "lucide-react";
import { Button } from "../ui/Button.js";
import { Badge } from "../ui/Badge.js";
import { cn } from "../../lib/utils.js";
import { useAiApi, useAiStatus } from "../../api/aiHooks.js";
import { useHostBridge } from "../../host/HostProvider.js";
import { AiFeedbackButtons } from "./AiFeedbackButtons.js";
import type { CommitDraftAssistResponse } from "../../api/aiApi.js";

interface CommitDraftAssistButtonProps {
  planId: string;
  commitId?: string | undefined;
  currentTitle: string;
  currentDescription?: string | undefined;
  currentSuccessCriteria?: string | undefined;
  currentEstimatePoints?: number | undefined;
  chessPiece?: string | undefined;
  onAcceptTitle?: ((title: string) => void) | undefined;
  onAcceptDescription?: ((description: string) => void) | undefined;
  onAcceptSuccessCriteria?: ((criteria: string) => void) | undefined;
  onAcceptEstimatePoints?: ((points: number) => void) | undefined;
  onAcceptChessPiece?: ((piece: string) => void) | undefined;
  className?: string | undefined;
}

interface SuggestionField {
  label: string;
  current: string;
  suggested: string;
  onAccept: () => void;
}

export function CommitDraftAssistButton({
  planId,
  commitId,
  currentTitle,
  currentDescription,
  currentSuccessCriteria,
  currentEstimatePoints,
  chessPiece,
  onAcceptTitle,
  onAcceptDescription,
  onAcceptSuccessCriteria,
  onAcceptEstimatePoints,
  onAcceptChessPiece,
  className,
}: CommitDraftAssistButtonProps) {
  const aiApi = useAiApi();
  const bridge = useHostBridge();
  const userId = bridge.context.authenticatedUser.id;
  const { data: aiStatus } = useAiStatus();
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState<CommitDraftAssistResponse | null>(null);
  const [accepted, setAccepted] = useState<Set<string>>(new Set());
  const [error, setError] = useState<string | null>(null);

  const isAvailable = aiStatus?.available ?? false;

  const handleRequest = useCallback(async () => {
    setLoading(true);
    setError(null);
    setResult(null);
    setAccepted(new Set());
    try {
      const response = await aiApi.commitDraftAssist({
        userId,
        planId,
        commitId,
        currentTitle,
        currentDescription,
        currentSuccessCriteria,
        currentEstimatePoints,
        chessPiece,
      });
      if (!response.aiAvailable) {
        setError("AI is currently unavailable. Try again later.");
        return;
      }
      setResult(response);
    } catch {
      setError("Failed to get AI suggestions.");
    } finally {
      setLoading(false);
    }
  }, [
    aiApi, userId, planId, commitId, currentTitle,
    currentDescription, currentSuccessCriteria, currentEstimatePoints, chessPiece,
  ]);

  const handleAccept = useCallback((field: string, acceptFn: () => void) => {
    acceptFn();
    setAccepted((prev) => new Set(prev).add(field));
  }, []);

  // Build suggestion fields from the response
  const suggestions: SuggestionField[] = [];
  if (result) {
    if (result.suggestedTitle && onAcceptTitle) {
      suggestions.push({
        label: "Title",
        current: currentTitle,
        suggested: result.suggestedTitle,
        onAccept: () => onAcceptTitle(result.suggestedTitle!),
      });
    }
    if (result.suggestedDescription && onAcceptDescription) {
      suggestions.push({
        label: "Description",
        current: currentDescription ?? "",
        suggested: result.suggestedDescription,
        onAccept: () => onAcceptDescription(result.suggestedDescription!),
      });
    }
    if (result.suggestedSuccessCriteria && onAcceptSuccessCriteria) {
      suggestions.push({
        label: "Success Criteria",
        current: currentSuccessCriteria ?? "",
        suggested: result.suggestedSuccessCriteria,
        onAccept: () => onAcceptSuccessCriteria(result.suggestedSuccessCriteria!),
      });
    }
    if (result.suggestedEstimatePoints != null && onAcceptEstimatePoints) {
      suggestions.push({
        label: "Estimate",
        current: currentEstimatePoints != null ? `${currentEstimatePoints} pts` : "not set",
        suggested: `${result.suggestedEstimatePoints} pts`,
        onAccept: () => onAcceptEstimatePoints(result.suggestedEstimatePoints!),
      });
    }
    if (result.suggestedChessPiece && onAcceptChessPiece) {
      suggestions.push({
        label: "Chess Piece",
        current: chessPiece ?? "not set",
        suggested: result.suggestedChessPiece,
        onAccept: () => onAcceptChessPiece(result.suggestedChessPiece!),
      });
    }
  }

  const allGood = result && suggestions.length === 0;

  return (
    <div className={cn("flex flex-col gap-2", className)}>
      {/* Trigger button */}
      <Button
        type="button"
        variant="ghost"
        size="sm"
        onClick={() => void handleRequest()}
        disabled={loading || !isAvailable || !currentTitle.trim()}
        data-testid="ai-draft-assist-btn"
        className="self-start text-primary hover:text-primary/80"
        title={!isAvailable ? "AI unavailable" : "Get AI suggestions for this commit"}
      >
        {loading ? (
          <Loader2 className="h-3.5 w-3.5 animate-spin mr-1" />
        ) : (
          <Sparkles className="h-3.5 w-3.5 mr-1" />
        )}
        {loading ? "Thinking…" : "AI Suggest"}
      </Button>

      {/* Error */}
      {error && (
        <p className="text-xs text-danger" data-testid="ai-draft-assist-error">{error}</p>
      )}

      {/* All good */}
      {allGood && (
        <div
          className="flex items-center gap-1.5 text-xs text-foreground bg-foreground/5 rounded-default px-2.5 py-1.5"
          data-testid="ai-draft-assist-good"
        >
          <Check className="h-3.5 w-3.5" />
          Looks good! No suggestions.
          {result.suggestionId && (
            <AiFeedbackButtons suggestionId={result.suggestionId} className="ml-auto" />
          )}
        </div>
      )}

      {/* Suggestions */}
      {suggestions.length > 0 && (
        <div
          className="rounded-default border border-primary/20 bg-primary/5 p-3 flex flex-col gap-2.5"
          data-testid="ai-draft-assist-suggestions"
        >
          <div className="flex items-center justify-between">
            <span className="text-xs font-semibold text-primary flex items-center gap-1">
              <Sparkles className="h-3 w-3" /> AI Suggestions
            </span>
            {result?.suggestionId && (
              <AiFeedbackButtons suggestionId={result.suggestionId} />
            )}
          </div>

          {suggestions.map((s) => {
            const isAccepted = accepted.has(s.label);
            return (
              <div
                key={s.label}
                className={cn(
                  "rounded-sm border px-2.5 py-2 text-xs",
                  isAccepted
                    ? "border-foreground/20 bg-foreground/5"
                    : "border-neutral-200 bg-white",
                )}
                data-testid={`ai-suggestion-${s.label.toLowerCase().replace(/\s/g, "-")}`}
              >
                <div className="flex items-start justify-between gap-2">
                  <div className="flex-1">
                    <Badge variant="default" className="mb-1 text-[0.6rem]">
                      {s.label}
                    </Badge>
                    {s.current && (
                      <p className="m-0 text-muted line-through">{s.current}</p>
                    )}
                    <p className="m-0 font-medium text-foreground">{s.suggested}</p>
                  </div>
                  {!isAccepted && (
                    <Button
                      type="button"
                      variant="ghost"
                      size="icon"
                      onClick={() => handleAccept(s.label, s.onAccept)}
                      className="h-6 w-6 text-foreground hover:bg-neutral-100 shrink-0"
                      aria-label={`Accept ${s.label} suggestion`}
                      data-testid={`ai-accept-${s.label.toLowerCase().replace(/\s/g, "-")}`}
                    >
                      <Check className="h-3.5 w-3.5" />
                    </Button>
                  )}
                  {isAccepted && (
                    <span className="text-[0.6rem] text-foreground font-semibold">✓ Applied</span>
                  )}
                </div>
              </div>
            );
          })}

          {result?.rationale && (
            <p className="m-0 text-[0.65rem] text-muted italic" data-testid="ai-draft-assist-rationale">
              {result.rationale}
            </p>
          )}
        </div>
      )}
    </div>
  );
}

